data.query:
query ListCycles($first: Int, $after: String, $updatedAfter: DateTimeOrDuration!) {
  cycles(first: $first, after: $after, filter: { updatedAt: { gte: $updatedAfter } }) {
    nodes {

  id
  name
  number
  description
  team { id }
  startsAt
  endsAt
  completedAt
  progress
  createdAt
  updatedAt

    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
